#include <bits/stdc++.h>using namespace std; // macros#define ll long long#define yes cout << "YES\n"#define no cout << "NO\n"#define f(i, size) for (int i = 0; i < size; i++)// #define ia(a, n) \//     int a[n];     \//     f(i, n) cin >> a[i] #define iv(v, n)     \    vector<ll> v(n); \    f(i, n) cin >> v[i] // #define M (1000000007)#define INF 1000000000000000000LL#define mp make_pair#define mt make_tuple #define nline '\n'#define pb push_back#define pii pair<int, int>#define pll pair<ll, ll>#define vii vector<pair<int, int>> void solve() {    int n, k;    cin >> n >> k;    vector<int> a(n);    for (int i = 0; i < n; i++) cin >> a[i];    int p;    cin >> p;    p--;     int x = a[p];    int ans = 0;    int l=0, r=n-1;    while(l<p){        if(a[l]!=x) break;        l++;    }    while(r>p){        if(a[r]!=x) break;        r--;    }    if(l>=r) {        cout << 0 << nline;        return;    }    while(l<p && r>p){        int u=a[l], v=a[r];        ans++;        while(l<p && a[l]==u) l++;        while(r>p && a[r]==v) r--;    }    while(l<p){        int u=a[l];        ans++;        while(l<p && a[l]==u) l++;    }    while(r>p){        int v=a[r];        ans++;        while(r>p && a[r]==v) r--;    }    if(ans&1) ans++;    cout << ans << nline;}  int main(){    ios::sync_with_stdio(false);    cin.tie(nullptr);    cout.tie(nullptr);     ll t;    cin >> t;    while (t--) {        solve();    }    return 0;}